export function resolveDishId(name?: string | null, dishId?: string | null): string | null {
  const id = dishId?.trim();
  if (id) return id;
  const key = normalizeDishName(name ?? '');
  return key ? DISH_NAME_TO_ID[key] ?? null : null;
}
